def validate(args, outputs):
    ops, arg_lists = args
    if not isinstance(outputs, list) or len(outputs) != len(ops):
        return False
    original = arg_lists[0][0]
    sorted_original = sorted(original)
    for i in range(1, len(ops)):
        op, out = ops[i], outputs[i]
        if op == 'reset':
            if out != original:
                return False
        elif op == 'shuffle':
            if not isinstance(out, list) or len(out) != len(original):
                return False
            if sorted(out) != sorted_original:
                return False
    return True

