function validate(args, outputs) {
  const [ops, argLists] = args;
  if (!Array.isArray(outputs) || outputs.length !== ops.length) return false;
  const original = argLists[0][0];
  const sortedOriginal = [...original].sort((a, b) => a - b);
  const arraysEqual = (a, b) => a.length === b.length && a.every((v, i) => v === b[i]);
  for (let i = 1; i < ops.length; i++) {
    const op = ops[i], out = outputs[i];
    if (op === 'reset') {
      if (!Array.isArray(out) || !arraysEqual(out, original)) return false;
    } else if (op === 'shuffle') {
      if (!Array.isArray(out) || out.length !== original.length) return false;
      const sortedOut = [...out].sort((a, b) => a - b);
      if (!arraysEqual(sortedOut, sortedOriginal)) return false;
    }
  }
  return true;
}

