def gen(rng, size):
    n = rng.randint(1, max(1, min(size, 50)))
    nums = [rng.randint(-1000000, 1000000) for _ in range(n)]
    ops = ['Solution']
    args = [[nums]]
    calls = max(1, min(size, 50))
    for _ in range(calls):
        if rng.random() < 0.5:
            ops.append('shuffle')
        else:
            ops.append('reset')
        args.append([])
    return [ops, args]

